import type { PublicCard } from '../../../types';

export const gcseFormulasCardsPart1: PublicCard[] = [
  // ── NUMBER FORMULAS (cards 1–30) ──────────────────────────────────────────
  { id: 'dc-gcse-formulas-0001', deck_id: 'deck-gcse-formulas', front: 'Formula: Percentage of an amount', back: 'Percentage of amount = (percentage / 100) × amount\n\nEquivalent: multiply by the decimal multiplier.\n  15% of £240 = 0.15 × 240 = £36\n\nGCSE Tip: Convert % to a decimal (÷100) first. "Of" always means multiply.', sort_order: 1 },
  { id: 'dc-gcse-formulas-0002', deck_id: 'deck-gcse-formulas', front: 'Formula: Percentage change', back: 'Percentage change = (change / original) × 100\n\nWhere change = new value − original value.\n  Positive result → increase\n  Negative result → decrease\n\nGCSE Tip: Always divide by the ORIGINAL, not the new value.', sort_order: 2 },
  { id: 'dc-gcse-formulas-0003', deck_id: 'deck-gcse-formulas', front: 'Formula: Multiplier for percentage increase/decrease', back: 'Increase by r%:  new = original × (1 + r/100)\n  e.g. 20% increase → multiply by 1.20\n\nDecrease by r%:  new = original × (1 − r/100)\n  e.g. 15% decrease → multiply by 0.85\n\nGCSE Tip: The multiplier method combines finding the percentage and applying it in a single step.', sort_order: 3 },
  { id: 'dc-gcse-formulas-0004', deck_id: 'deck-gcse-formulas', front: 'Formula: Reverse percentage (finding the original)', back: 'original = final amount / multiplier\n\nExample: after 20% increase → final = 1.20 × original\n  original = final ÷ 1.20\n\nExample: after 35% decrease → final = 0.65 × original\n  original = final ÷ 0.65\n\nGCSE Tip: NEVER take the percentage off the final value — divide by the multiplier.', sort_order: 4 },
  { id: 'dc-gcse-formulas-0005', deck_id: 'deck-gcse-formulas', front: 'Formula: Simple interest', back: 'I = PRT / 100\n\n  I = interest earned (£)\n  P = principal (initial amount, £)\n  R = annual interest rate (%)\n  T = time (years)\n\nTotal amount = P + I\n\nGCSE Tip: Simple interest is calculated on the original principal every year — it does NOT compound.', sort_order: 5 },
  { id: 'dc-gcse-formulas-0006', deck_id: 'deck-gcse-formulas', front: 'Formula: Compound interest / repeated percentage change', back: 'A = P(1 + r/100)ⁿ    (growth)\nA = P(1 − r/100)ⁿ    (decay)\n\n  A = final amount\n  P = initial amount (principal)\n  r = rate per period (%)\n  n = number of periods\n\nGCSE Tip: This also models population growth, radioactive decay, and depreciation.', sort_order: 6 },
  { id: 'dc-gcse-formulas-0007', deck_id: 'deck-gcse-formulas', front: 'Formula: Speed, distance, and time', back: 'Speed = Distance / Time\nDistance = Speed × Time\nTime = Distance / Speed\n\nMemory aid: cover the quantity you want in the triangle.\n  D\n S × T\n\nGCSE Tip: Units must match. Convert minutes to hours by dividing by 60 before using km/h.', sort_order: 7 },
  { id: 'dc-gcse-formulas-0008', deck_id: 'deck-gcse-formulas', front: 'Formula: Density, mass, and volume', back: 'Density = Mass / Volume\nMass = Density × Volume\nVolume = Mass / Density\n\nUnits: g/cm³ or kg/m³\n\nMemory aid: triangle (same layout as S,D,T):\n  M\nD × V\n\nGCSE Tip: Pay attention to units — the question may give mass in grams but volume in m³.', sort_order: 8 },
  { id: 'dc-gcse-formulas-0009', deck_id: 'deck-gcse-formulas', front: 'Formula: Pressure, force, and area', back: 'Pressure = Force / Area\nForce = Pressure × Area\nArea = Force / Pressure\n\nUnits: pascals (Pa) = N/m²; or N/cm²\n\nGCSE Tip: Same triangle structure as density and speed. Convert area to matching units before using the formula.', sort_order: 9 },
  { id: 'dc-gcse-formulas-0010', deck_id: 'deck-gcse-formulas', front: 'Formula: HCF using prime factorisation', back: 'HCF(a, b) = product of shared prime factors (using the LOWER power of each)\n\nExample: 360 = 2³×3²×5; 756 = 2²×3³×7\n  Shared: 2² and 3²\n  HCF = 4 × 9 = 36\n\nGCSE Tip: In a Venn diagram, HCF = product of numbers in the OVERLAP (intersection).', sort_order: 10 },
  { id: 'dc-gcse-formulas-0011', deck_id: 'deck-gcse-formulas', front: 'Formula: LCM using prime factorisation', back: 'LCM(a, b) = product of ALL prime factors, using the HIGHER power of each\n\nExample: 360 = 2³×3²×5; 756 = 2²×3³×7\n  Take: 2³, 3³, 5, 7\n  LCM = 8 × 27 × 5 × 7 = 7560\n\nRelationship: HCF × LCM = a × b (only for two numbers)\n\nGCSE Tip: In a Venn diagram, LCM = product of ALL numbers in both circles.', sort_order: 11 },
  { id: 'dc-gcse-formulas-0012', deck_id: 'deck-gcse-formulas', front: 'Formula: Index laws — multiplication and division', back: 'Multiply (same base): aᵐ × aⁿ = aᵐ⁺ⁿ\nDivide (same base): aᵐ ÷ aⁿ = aᵐ⁻ⁿ\nPower of power: (aᵐ)ⁿ = aᵐⁿ\n\nExample: x³ × x⁵ = x⁸;  x⁸ ÷ x³ = x⁵;  (x²)³ = x⁶\n\nGCSE Tip: The bases must be the same. These rules do NOT apply when multiplying different bases (e.g. 2³ × 3² ≠ 6⁵).', sort_order: 12 },
  { id: 'dc-gcse-formulas-0013', deck_id: 'deck-gcse-formulas', front: 'Formula: Zero, negative, and fractional indices', back: 'Zero: a⁰ = 1 (for any a ≠ 0)\nNegative: a⁻ⁿ = 1/aⁿ\nFraction: a^(1/n) = ⁿ√a\nFraction (general): a^(m/n) = (ⁿ√a)ᵐ\n\nExamples:\n  5⁻² = 1/25\n  8^(1/3) = ∛8 = 2\n  27^(2/3) = (∛27)² = 3² = 9\n\nGCSE Tip: For a^(m/n): take the root FIRST (gives smaller numbers), then apply the power.', sort_order: 13 },
  { id: 'dc-gcse-formulas-0014', deck_id: 'deck-gcse-formulas', front: 'Formula: Standard form (scientific notation)', back: 'A × 10ⁿ   where 1 ≤ A < 10 and n is an integer.\n\nMultiply: (A × 10ᵐ) × (B × 10ⁿ) = AB × 10ᵐ⁺ⁿ\nDivide:   (A × 10ᵐ) ÷ (B × 10ⁿ) = (A/B) × 10ᵐ⁻ⁿ\n\nAdjust A if needed (if A ≥ 10 or A < 1, adjust and change n).\n\nGCSE Tip: Moving decimal point RIGHT → more negative power; LEFT → more positive power.', sort_order: 14 },
  { id: 'dc-gcse-formulas-0015', deck_id: 'deck-gcse-formulas', front: 'Formula: Error interval (bounds of a rounded value)', back: 'Lower bound = stated value − ½ × (unit of accuracy)\nUpper bound = stated value + ½ × (unit of accuracy)\n\nNotation: LB ≤ x < UB\n\nExample: 8.4 cm (to 1 d.p.)\n  LB = 8.35 cm;  UB = 8.45 cm\n  Error interval: 8.35 ≤ x < 8.45\n\nGCSE Tip: Upper bound uses strict inequality < (not ≤). The UB is exclusive.', sort_order: 15 },
  { id: 'dc-gcse-formulas-0016', deck_id: 'deck-gcse-formulas', front: 'Formula: Maximum and minimum of calculated values', back: 'To MAXIMISE a result:\n  Addition / multiplication → use upper bounds (UB)\n  Division a/b → use UB of a and LB of b\n\nTo MINIMISE a result:\n  Addition / multiplication → use lower bounds (LB)\n  Division a/b → use LB of a and UB of b\n\nGCSE Tip: Always identify which bounds make the answer larger or smaller. State clearly which bounds you are using.', sort_order: 16 },
  { id: 'dc-gcse-formulas-0017', deck_id: 'deck-gcse-formulas', front: 'Formula: Profit, loss, and profit percentage', back: 'Profit = selling price − cost price  (positive means profit)\nLoss = cost price − selling price   (positive means loss)\n\nProfit % = (profit / cost price) × 100\nLoss %   = (loss / cost price) × 100\n\nGCSE Tip: Profit/loss percentages are ALWAYS calculated on the COST PRICE (original value), not the selling price.', sort_order: 17 },
  { id: 'dc-gcse-formulas-0018', deck_id: 'deck-gcse-formulas', front: 'Formula: Direct proportion', back: 'y is directly proportional to x:  y ∝ x  →  y = kx\n  (k = constant of proportionality = y/x)\n\ny ∝ x²  →  y = kx²\ny ∝ √x  →  y = k√x\ny ∝ xⁿ  →  y = kxⁿ\n\nGCSE Tip: Find k by substituting the known (x, y) pair. Graph of y = kx is a straight line through the origin.', sort_order: 18 },
  { id: 'dc-gcse-formulas-0019', deck_id: 'deck-gcse-formulas', front: 'Formula: Inverse proportion', back: 'y is inversely proportional to x:  y ∝ 1/x  →  y = k/x\n  (k = xy = constant)\n\ny ∝ 1/x²  →  y = k/x²\ny ∝ 1/√x  →  y = k/√x\n\nGCSE Tip: Find k by substituting known values. Graph of y = k/x is a hyperbola — two branches, never touching the axes.', sort_order: 19 },
  { id: 'dc-gcse-formulas-0020', deck_id: 'deck-gcse-formulas', front: 'Formula: Population density', back: 'Population density = population / area\n\nRearrangements:\n  Population = density × area\n  Area = population / density\n\nUnits: people per km² or people per m²\n\nGCSE Tip: Same triangle structure as density = mass/volume. Memorise the formula — it appears in contextual application questions.', sort_order: 20 },
  { id: 'dc-gcse-formulas-0021', deck_id: 'deck-gcse-formulas', front: 'Formula: Ratio — sharing in a given ratio', back: 'To share amount T in ratio a:b:c (and so on):\n  Total parts = a + b + c\n  1 part = T / total parts\n  Each share = (part value) × ratio number\n\nExample: Share £280 in 2:3:5\n  Total parts = 10; 1 part = £28\n  Shares: £56, £84, £140\n\nGCSE Tip: Check: sum of all shares = original amount.', sort_order: 21 },
  { id: 'dc-gcse-formulas-0022', deck_id: 'deck-gcse-formulas', front: 'Formula: Scale and map reading', back: 'Map scale 1:n\n  Real distance = map distance × n\n  Map distance = real distance / n\n\nExample: Scale 1:25 000; map distance = 6 cm\n  Real = 6 × 25 000 = 150 000 cm = 1.5 km\n\nGCSE Tip: Convert the real distance to sensible units at the end (usually km for large scales). Keep track of unit conversions.', sort_order: 22 },
  { id: 'dc-gcse-formulas-0023', deck_id: 'deck-gcse-formulas', front: 'Formula: Unit conversion for area and volume', back: 'Area:\n  × 100²  = × 10 000 when converting m² → cm²\n  × 100² again for cm² → mm²\n\nVolume:\n  × 100³  = × 1 000 000 when converting m³ → cm³\n  × 1000 for litres → cm³ (1 L = 1000 cm³)\n\nGCSE Tip: Square the linear factor for area; cube it for volume. 1 m = 100 cm → 1 m² = 10 000 cm² → 1 m³ = 1 000 000 cm³.', sort_order: 23 },
  { id: 'dc-gcse-formulas-0024', deck_id: 'deck-gcse-formulas', front: 'Formula: Converting a recurring decimal to a fraction', back: 'Let x = the recurring decimal.\nMultiply by 10ⁿ where n = number of recurring digits.\nSubtract to eliminate the recurring part.\n\nExample: x = 0.272727…\n  100x = 27.2727…\n  99x = 27\n  x = 27/99 = 3/11\n\nGCSE Tip: Number of 9s in denominator = number of recurring digits. For 0.1̄6̄: 99x needs adjustment.', sort_order: 24 },
  { id: 'dc-gcse-formulas-0025', deck_id: 'deck-gcse-formulas', front: 'Formula: Surd simplification', back: '√(a × b) = √a × √b\n√(a² × b) = a√b\n\nRules:\n  √a × √a = a\n  √a × √b = √(ab)\n  k√a + m√a = (k+m)√a  (only add LIKE surds)\n\nSimplify: √72 = √(36 × 2) = 6√2\n\nGCSE Tip: Find the largest perfect square factor. Perfect squares: 4, 9, 16, 25, 36, 49, 64, 81, 100…', sort_order: 25 },
  { id: 'dc-gcse-formulas-0026', deck_id: 'deck-gcse-formulas', front: 'Formula: Rationalising the denominator', back: '1/√a  →  multiply by √a/√a  →  √a/a\n\n1/(a + √b)  →  multiply by (a − √b)/(a − √b)\n  Result: (a − √b) / (a² − b)\n\nExample: 1/(3 + √5) = (3−√5)/((3+√5)(3−√5)) = (3−√5)/(9−5) = (3−√5)/4\n\nGCSE Tip: The denominator becomes rational because (a+√b)(a−√b) = a² − b.', sort_order: 26 },
  { id: 'dc-gcse-formulas-0027', deck_id: 'deck-gcse-formulas', front: 'Formula: VAT calculation', back: 'Price including 20% VAT = original × 1.20\nVAT amount = original × 0.20\n\nTo find pre-VAT price from VAT-inclusive price:\n  original = VAT-inclusive price ÷ 1.20\n\nExample: Price including VAT = £360\n  Pre-VAT = 360 ÷ 1.20 = £300\n  VAT amount = £60\n\nGCSE Tip: Never calculate 20% of the inclusive price — always divide by 1.20.', sort_order: 27 },
  { id: 'dc-gcse-formulas-0028', deck_id: 'deck-gcse-formulas', front: 'Formula: Combined percentage changes (multiplier method)', back: 'Apply each multiplier in sequence:\n  final = original × m₁ × m₂ × m₃ × …\n\nExample: increase 10% then decrease 5%:\n  final = original × 1.10 × 0.95 = original × 1.045\n  Net result: 4.5% increase\n\nGCSE Tip: Do NOT add or subtract percentages. Multipliers are combined by multiplication. The order does not affect the result.', sort_order: 28 },
  { id: 'dc-gcse-formulas-0029', deck_id: 'deck-gcse-formulas', front: 'Formula: Expressing one quantity as a percentage of another', back: '(Part / Whole) × 100 = percentage\n\nBoth quantities must be in the same units.\n\nExample: A test score of 36 out of 48\n  (36/48) × 100 = 75%\n\nExample: 450 m as a percentage of 2 km\n  Convert: 2 km = 2000 m\n  (450/2000) × 100 = 22.5%\n\nGCSE Tip: Convert to the same unit BEFORE dividing.', sort_order: 29 },
  { id: 'dc-gcse-formulas-0030', deck_id: 'deck-gcse-formulas', front: 'Formula: Unitary method', back: 'Find the value of one unit, then scale.\n\n1 unit = given amount / given number of units\nRequired = 1 unit value × required number of units\n\nExample: 4 kg costs £6.80\n  1 kg = £6.80/4 = £1.70\n  7 kg = 7 × £1.70 = £11.90\n\nGCSE Tip: Also used for best-buy comparisons (calculate cost per gram/item) and for recipe scaling.', sort_order: 30 },

  // ── ALGEBRA FORMULAS (cards 31–70) ────────────────────────────────────────
  { id: 'dc-gcse-formulas-0031', deck_id: 'deck-gcse-formulas', front: 'Formula: The quadratic formula', back: 'For ax² + bx + c = 0 (a ≠ 0):\n\n  x = (−b ± √(b² − 4ac)) / (2a)\n\nGives both solutions when they exist.\n\nGCSE Tip: MEMORISE this formula. Identify a, b, c carefully (watch signs). b² − 4ac is the discriminant — its sign tells you how many real solutions exist.', sort_order: 31 },
  { id: 'dc-gcse-formulas-0032', deck_id: 'deck-gcse-formulas', front: 'Formula: The discriminant', back: 'Δ = b² − 4ac   (for ax² + bx + c = 0)\n\n  Δ > 0  →  two distinct real roots\n  Δ = 0  →  one repeated (equal) root\n  Δ < 0  →  no real roots\n\nGCSE Tip: Use to determine the number of solutions without solving. Set Δ = 0 to find the value of an unknown that gives equal roots.', sort_order: 32 },
  { id: 'dc-gcse-formulas-0033', deck_id: 'deck-gcse-formulas', front: 'Formula: Completing the square', back: 'x² + bx + c = (x + b/2)² − (b/2)² + c\n\nFor ax² + bx + c: factor out a first.\n  ax² + bx + c = a(x + b/2a)² − b²/4a + c\n\nThe vertex of y = a(x − h)² + k is at (h, k).\n\nGCSE Tip: "Complete the square" → identify vertex, solve quadratics, prove minimum/maximum. Always balance: what you add inside the bracket must be subtracted outside.', sort_order: 33 },
  { id: 'dc-gcse-formulas-0034', deck_id: 'deck-gcse-formulas', front: 'Formula: nth term of an arithmetic (linear) sequence', back: 'Tₙ = a + (n − 1)d  =  dn + (a − d)\n\n  a = first term\n  d = common difference (= T₂ − T₁)\n\nAlternatively: Tₙ = dn + c where c = T₁ − d\n\nExample: 3, 7, 11, 15 … → d = 4, a = 3 → Tₙ = 4n − 1\n\nGCSE Tip: The coefficient of n equals the common difference d. To test: substitute n = 1 to check T₁ = a.', sort_order: 34 },
  { id: 'dc-gcse-formulas-0035', deck_id: 'deck-gcse-formulas', front: 'Formula: nth term of a quadratic sequence', back: 'If second differences are constant and equal to 2a:\n  The nth term starts with an².\n\nMethod:\n  1. Find 2nd difference → coefficient of n² = (2nd difference)/2\n  2. Subtract an² from each term\n  3. Find nth term of the remaining linear sequence\n  4. Combine\n\nExample: 5, 12, 23, 38 → 2nd diff = 4 → 2n² → subtract: 3, 4, 5, 6 → n+2 → Tₙ = 2n² + n + 2\n\nGCSE Tip: The 2nd difference being constant confirms a quadratic sequence.', sort_order: 35 },
  { id: 'dc-gcse-formulas-0036', deck_id: 'deck-gcse-formulas', front: 'Formula: nth term of a geometric sequence', back: 'Tₙ = a × rⁿ⁻¹\n\n  a = first term\n  r = common ratio (= T₂/T₁)\n\nExample: 3, 6, 12, 24 → a = 3, r = 2 → Tₙ = 3 × 2ⁿ⁻¹\n  T₅ = 3 × 2⁴ = 48\n\nGCSE Tip: Verify with n = 1: T₁ = a × r⁰ = a ✓. A negative r gives alternating signs.', sort_order: 36 },
  { id: 'dc-gcse-formulas-0037', deck_id: 'deck-gcse-formulas', front: 'Formula: Sum of an arithmetic series', back: 'Sₙ = n/2 × (2a + (n−1)d)\n  or equivalently:\n  Sₙ = n/2 × (first term + last term)\n\n  n = number of terms\n  a = first term\n  d = common difference\n\nExample: Sum of first 20 natural numbers:\n  S₂₀ = 20/2 × (1 + 20) = 10 × 21 = 210\n\nGCSE Tip: Sum of 1+2+…+n = n(n+1)/2.', sort_order: 37 },
  { id: 'dc-gcse-formulas-0038', deck_id: 'deck-gcse-formulas', front: 'Formula: Gradient of a straight line', back: 'm = (y₂ − y₁) / (x₂ − x₁)\n\nFor the line y = mx + c: gradient = m\n\nParallel lines: equal gradients (m₁ = m₂)\nPerpendicular lines: m₁ × m₂ = −1\n  → m₂ = −1/m₁ (negative reciprocal)\n\nGCSE Tip: Horizontal lines: m = 0. Vertical lines: m is undefined. Perpendicular: flip the fraction and change the sign.', sort_order: 38 },
  { id: 'dc-gcse-formulas-0039', deck_id: 'deck-gcse-formulas', front: 'Formula: Equation of a straight line (gradient-intercept)', back: 'y = mx + c\n\n  m = gradient\n  c = y-intercept\n\nGiven gradient m and point (x₁, y₁):\n  y − y₁ = m(x − x₁)  (point-slope form)\n\nSteps: find m, substitute one point to find c.\n\nGCSE Tip: Always rearrange to y = mx + c as your final answer unless a different form is asked for.', sort_order: 39 },
  { id: 'dc-gcse-formulas-0040', deck_id: 'deck-gcse-formulas', front: 'Formula: Distance between two points', back: 'd = √[(x₂ − x₁)² + (y₂ − y₁)²]\n\nThis is Pythagoras applied to coordinates.\n\nExample: A(1, 2) and B(5, 5)\n  d = √[(5−1)² + (5−2)²] = √[16 + 9] = √25 = 5\n\nGCSE Tip: Write out the substitution clearly. Square the differences first, then add, then square root.', sort_order: 40 },
  { id: 'dc-gcse-formulas-0041', deck_id: 'deck-gcse-formulas', front: 'Formula: Midpoint of a line segment', back: 'Midpoint = ((x₁ + x₂)/2 , (y₁ + y₂)/2)\n\nSimply average the x-coordinates and average the y-coordinates.\n\nExample: A(3, 1) and B(7, 5)\n  Midpoint = (5, 3)\n\nGCSE Tip: Used when finding the perpendicular bisector (midpoint + perpendicular gradient).', sort_order: 41 },
  { id: 'dc-gcse-formulas-0042', deck_id: 'deck-gcse-formulas', front: 'Formula: Equation of a circle (centred at origin)', back: 'x² + y² = r²\n\nwhere r = radius.\n\nFor a circle centred at (a, b):\n  (x − a)² + (y − b)² = r²\n\nGCSE Tip: To find the equation of a tangent at point (x₁, y₁) on x²+y²=r²:\n  Radius gradient = y₁/x₁\n  Tangent gradient = −x₁/y₁\n  Then use y − y₁ = m(x − x₁).', sort_order: 42 },
  { id: 'dc-gcse-formulas-0043', deck_id: 'deck-gcse-formulas', front: 'Formula: Algebraic identities (key expansions)', back: '(a + b)² = a² + 2ab + b²\n(a − b)² = a² − 2ab + b²\n(a + b)(a − b) = a² − b²  ← difference of two squares\n(a + b)³ = a³ + 3a²b + 3ab² + b³\n(a − b)³ = a³ − 3a²b + 3ab² − b³\n\nGCSE Tip: The difference of two squares (a+b)(a−b) = a² − b² is extremely useful for factorising and simplifying.', sort_order: 43 },
  { id: 'dc-gcse-formulas-0044', deck_id: 'deck-gcse-formulas', front: 'Formula: Sum and product of roots (Vieta\'s formulas)', back: 'For ax² + bx + c = 0 with roots α and β:\n\n  Sum of roots:    α + β = −b/a\n  Product of roots: αβ = c/a\n\nExample: 2x² − 5x + 3 = 0\n  Sum = 5/2;  Product = 3/2\n\nGCSE Tip: Used to find the sum or product of roots WITHOUT solving. Also used in proof and construction problems.', sort_order: 44 },
  { id: 'dc-gcse-formulas-0045', deck_id: 'deck-gcse-formulas', front: 'Formula: Vertex of a parabola y = ax² + bx + c', back: 'x-coordinate of vertex: x = −b/(2a)\nSubstitute into the equation to find y.\n\nOR by completing the square:\n  y = a(x − h)² + k → vertex at (h, k)\n\nExample: y = 2x² − 8x + 3\n  x = 8/4 = 2;  y = 2(4) − 16 + 3 = −5\n  Vertex: (2, −5) — minimum point (a > 0)\n\nGCSE Tip: The axis of symmetry is the vertical line x = −b/(2a).', sort_order: 45 },
  { id: 'dc-gcse-formulas-0046', deck_id: 'deck-gcse-formulas', front: 'Formula: Factorising the difference of two squares', back: 'a² − b² = (a + b)(a − b)\n\nExamples:\n  x² − 25 = (x + 5)(x − 5)\n  9x² − 16 = (3x + 4)(3x − 4)\n  x⁴ − 1 = (x² + 1)(x² − 1) = (x² + 1)(x + 1)(x − 1)\n\nGCSE Tip: Recognise both terms must be perfect squares and there is a minus sign between them. This form also works for simplifying fractions and solving equations.', sort_order: 46 },
  { id: 'dc-gcse-formulas-0047', deck_id: 'deck-gcse-formulas', front: 'Formula: Composite and inverse functions', back: 'Composite: fg(x) = f(g(x)) — apply g first, then f.\n\nInverse: f⁻¹(x) — swap x and y in y = f(x), then solve for y.\n  f(f⁻¹(x)) = x for all x in domain.\n\nExample: f(x) = 2x + 3\n  y = 2x + 3 → x = 2y + 3 → y = (x−3)/2\n  f⁻¹(x) = (x − 3)/2\n\nGCSE Tip: fg ≠ gf. Always apply the RIGHTMOST function first in composite notation.', sort_order: 47 },
  { id: 'dc-gcse-formulas-0048', deck_id: 'deck-gcse-formulas', front: 'Formula: Graph transformations summary', back: 'y = f(x) + a   → translate UP by a\ny = f(x + a)   → translate LEFT by a\ny = af(x)      → stretch vertically by factor a\ny = f(ax)      → stretch horizontally by 1/a\ny = −f(x)      → reflect in x-axis\ny = f(−x)      → reflect in y-axis\n\nGCSE Tip: Changes INSIDE f() affect x (horizontal, counter-intuitive direction). Changes OUTSIDE f() affect y (vertical, intuitive direction).', sort_order: 48 },
  { id: 'dc-gcse-formulas-0049', deck_id: 'deck-gcse-formulas', front: 'Formula: Solving simultaneous equations (substitution)', back: 'Step 1: Rearrange one equation to isolate one variable.\nStep 2: Substitute into the other equation.\nStep 3: Solve the resulting equation.\nStep 4: Back-substitute to find the other variable.\n\nFor a linear + quadratic pair: always substitute the LINEAR into the quadratic.\n\nGCSE Tip: After finding x-values, substitute into the linear equation (simpler) to find y. Always check both solutions in BOTH original equations.', sort_order: 49 },
  { id: 'dc-gcse-formulas-0050', deck_id: 'deck-gcse-formulas', front: 'Formula: Solving simultaneous equations (elimination)', back: 'Step 1: Multiply equations to match a coefficient.\nStep 2: Add or subtract to eliminate one variable.\nStep 3: Solve for the remaining variable.\nStep 4: Substitute back to find the other.\n\nExample: 3x + 2y = 12 and 5x − 2y = 4\n  Add: 8x = 16 → x = 2 → y = 3\n\nGCSE Tip: Add when coefficients have OPPOSITE signs; subtract when they are the SAME sign.', sort_order: 50 },
  { id: 'dc-gcse-formulas-0051', deck_id: 'deck-gcse-formulas', front: 'Formula: Rearranging formulae (change of subject)', back: 'Treat the formula as an equation and apply inverse operations:\n  1. Remove fractions (multiply)\n  2. Expand brackets\n  3. Collect terms with the new subject\n  4. Factorise if needed\n  5. Divide to isolate\n\nHarder example (subject appears twice):\n  Make x the subject of ax + b = cx + d\n  ax − cx = d − b → x(a−c) = d−b → x = (d−b)/(a−c)\n\nGCSE Tip: If the new subject appears in two terms, factorise it out first.', sort_order: 51 },
  { id: 'dc-gcse-formulas-0052', deck_id: 'deck-gcse-formulas', front: 'Formula: Iteration', back: 'xₙ₊₁ = g(xₙ)\n\nRearrange equation to x = g(x), choose starting value x₀, apply repeatedly until convergence.\n\nExample: x³ − 2x = 5 → x = ∛(2x + 5)\n  x₀ = 2: x₁ = ∛9 ≈ 2.0801;\n  x₂ = ∛(4.1602+5) = ∛9.1602 ≈ 2.0877; → converges\n\nGCSE Tip: Use 4+ decimal places throughout. Show at least 3 iterations. State how you know it converges (consecutive values agree to required accuracy).', sort_order: 52 },
  { id: 'dc-gcse-formulas-0053', deck_id: 'deck-gcse-formulas', front: 'Formula: The factor theorem', back: 'For a polynomial f(x):\n  (x − a) is a factor of f(x)  ⟺  f(a) = 0\n\nUse to find factors of cubics and higher-degree polynomials.\n\nExample: f(x) = x³ − 7x + 6\n  f(1) = 1 − 7 + 6 = 0 → (x − 1) is a factor.\n  Divide: f(x) = (x−1)(x²+x−6) = (x−1)(x+3)(x−2)\n\nGCSE Tip: Test small integers ±1, ±2, ±3 first.', sort_order: 53 },
  { id: 'dc-gcse-formulas-0054', deck_id: 'deck-gcse-formulas', front: 'Formula: Solving linear inequalities', back: 'Solve exactly like an equation EXCEPT:\n  Multiplying or dividing by a NEGATIVE number reverses the inequality sign.\n\nExample: −3x + 1 > 10\n  −3x > 9\n  x < −3  (sign reverses when ÷ by −3)\n\nGCSE Tip: State integer solutions when asked. Show on a number line. Open circle (○) = strict inequality; closed circle (●) = included endpoint.', sort_order: 54 },
  { id: 'dc-gcse-formulas-0055', deck_id: 'deck-gcse-formulas', front: 'Formula: Solving quadratic inequalities', back: 'Step 1: Solve the quadratic equation = 0 to find roots α and β (α < β).\nStep 2: Sketch the parabola.\nStep 3: Identify the region:\n  • ax² + bx + c < 0 (a>0): α < x < β  (between the roots)\n  • ax² + bx + c > 0 (a>0): x < α or x > β  (outside the roots)\n\nExample: x² − 5x + 6 ≤ 0 → (x−2)(x−3) ≤ 0 → 2 ≤ x ≤ 3\n\nGCSE Tip: Sketch the parabola to see which region satisfies the inequality.', sort_order: 55 },
  { id: 'dc-gcse-formulas-0056', deck_id: 'deck-gcse-formulas', front: 'Formula: Algebraic proof — common representations', back: 'Integer: n\nEven integer: 2n\nOdd integer: 2n + 1\nConsecutive integers: n, n+1, n+2\nConsecutive even: 2n, 2n+2, 2n+4\nConsecutive odd: 2n+1, 2n+3, 2n+5\nMultiple of k: kn\nSquare number: n²\n\nGCSE Tip: Define ALL letters at the start: "let n be an integer". Manipulate algebraically to show the required property (even = 2k form; divisible by 3 = 3k form).', sort_order: 56 },
  { id: 'dc-gcse-formulas-0057', deck_id: 'deck-gcse-formulas', front: 'Formula: Vector addition and subtraction', back: 'Column vectors:\n  (a/b) + (c/d) = (a+c / b+d)\n  (a/b) − (c/d) = (a−c / b−d)\n  k(a/b) = (ka / kb)\n\nMagnitude: |(a/b)| = √(a² + b²)\n\nGCSE Tip: Add/subtract corresponding components. The magnitude uses Pythagoras. A unit vector = vector divided by its magnitude.', sort_order: 57 },
  { id: 'dc-gcse-formulas-0058', deck_id: 'deck-gcse-formulas', front: 'Formula: Collinearity of points using vectors', back: 'Points A, B, C are collinear if:\n  AB = k × AC  for some scalar k\n(i.e. the vectors are parallel AND share a common point)\n\nOR: the gradient from A to B equals the gradient from A to C.\n\nGCSE Tip: In vector proof, show (1) the vectors are scalar multiples of each other, and (2) they share a common point. Both conditions are required.', sort_order: 58 },
  { id: 'dc-gcse-formulas-0059', deck_id: 'deck-gcse-formulas', front: 'Formula: Dividing a line in a given ratio using vectors', back: 'Point P divides AB in ratio m:n from A:\n  OP = OA + (m/(m+n)) × AB\n\nwhere AB = OB − OA.\n\nExample: P divides AB in ratio 1:2\n  OP = OA + (1/3)(OB − OA) = (2/3)OA + (1/3)OB\n\nGCSE Tip: P closer to A when m is smaller. Check: if m=0 → P=A; if m=1, n=0 → P=B.', sort_order: 59 },
  { id: 'dc-gcse-formulas-0060', deck_id: 'deck-gcse-formulas', front: 'Formula: Geometric transformations — rotation (about origin)', back: '90° clockwise:      (x, y) → (y, −x)\n90° anticlockwise:   (x, y) → (−y, x)\n180°:               (x, y) → (−x, −y)\n\nFor rotation about a point (a, b): translate to origin first, rotate, translate back.\n\nGCSE Tip: Use tracing paper in the exam to check. Always state: angle, direction (CW or CCW), and centre of rotation.', sort_order: 60 },
  { id: 'dc-gcse-formulas-0061', deck_id: 'deck-gcse-formulas', front: 'Formula: Geometric transformations — reflection', back: 'Reflection in x-axis:  (x, y) → (x, −y)\nReflection in y-axis:  (x, y) → (−x, y)\nReflection in y = x:   (x, y) → (y, x)\nReflection in y = −x:  (x, y) → (−y, −x)\nReflection in x = k:   (x, y) → (2k−x, y)\nReflection in y = k:   (x, y) → (x, 2k−y)\n\nGCSE Tip: The graph of f⁻¹(x) is the reflection of y = f(x) in the line y = x.', sort_order: 61 },
  { id: 'dc-gcse-formulas-0062', deck_id: 'deck-gcse-formulas', front: 'Formula: Enlargement — coordinates', back: 'Enlargement with scale factor k, centre (cx, cy):\n  New x = cx + k(old x − cx)\n  New y = cy + k(old y − cy)\n\nEquivalently: multiply the distance from the centre by k.\n\nNegative k: image is on the OPPOSITE side of the centre, and inverted.\n\nGCSE Tip: Always state: scale factor and centre. For a fractional k (0<k<1), the image is smaller.', sort_order: 62 },
  { id: 'dc-gcse-formulas-0063', deck_id: 'deck-gcse-formulas', front: 'Formula: Area and volume scale factors', back: 'If linear scale factor = k:\n  Area scale factor = k²\n  Volume scale factor = k³\n\nGiven area ratio, find k: k = √(area ratio)\nGiven volume ratio, find k: k = ∛(volume ratio)\n\nExample: k = 3 → areas are 9× larger; volumes are 27× larger.\n\nGCSE Tip: A very common Higher exam question. Apply to surface area AND cross-section area.', sort_order: 63 },
  { id: 'dc-gcse-formulas-0064', deck_id: 'deck-gcse-formulas', front: 'Formula: Gradient from a graph (tangent method)', back: 'Draw a tangent at the desired point (a straight line just touching the curve).\n\nGradient = rise / run = (y₂ − y₁) / (x₂ − x₁)\n\nChoose two points FAR apart on the tangent for accuracy.\n\nGCSE Tip: The tangent should touch — not cross — the curve at that point. The gradient gives the instantaneous rate of change at that point.', sort_order: 64 },
  { id: 'dc-gcse-formulas-0065', deck_id: 'deck-gcse-formulas', front: 'Formula: Area under a graph (trapezium rule)', back: 'Area ≈ h/2 × [y₀ + 2(y₁ + y₂ + … + yₙ₋₁) + yₙ]\n\n  h = width of each strip\n  y₀, y₁, …, yₙ = heights at each boundary\n\nArea = distance (for velocity-time graphs).\n\nGCSE Tip: More strips = better approximation. Concave down curves → overestimate; concave up → underestimate.', sort_order: 65 },
  { id: 'dc-gcse-formulas-0066', deck_id: 'deck-gcse-formulas', front: 'Formula: Discriminant for tangency (line meets curve)', back: 'To find when a line is tangent to a curve:\n1. Substitute line into curve → quadratic equation.\n2. Set discriminant = 0 (tangent ↔ exactly one intersection).\n3. Solve for the unknown.\n\nExample: y = x + c is tangent to y = x²\n  x² = x + c → x² − x − c = 0\n  Discriminant = 1 + 4c = 0 → c = −1/4\n\nGCSE Tip: This combines the circle/curve equation with a discriminant condition.', sort_order: 66 },
  { id: 'dc-gcse-formulas-0067', deck_id: 'deck-gcse-formulas', front: 'Formula: Simplifying algebraic fractions', back: 'Factor both numerator and denominator, then cancel common factors.\n\nExample:\n  (2x² + 5x + 3) / (2x² + x − 1)\n  = (2x + 3)(x + 1) / (2x − 1)(x + 1)\n  = (2x + 3) / (2x − 1)  [provided x ≠ −1]\n\nGCSE Tip: NEVER cancel individual terms — only complete FACTORS. Always factorise fully before cancelling.', sort_order: 67 },
  { id: 'dc-gcse-formulas-0068', deck_id: 'deck-gcse-formulas', front: 'Formula: Adding/subtracting algebraic fractions', back: 'Find the LCM of the denominators, rewrite each fraction, then add/subtract numerators.\n\nExample:\n  2/x + 3/(x−1) = [2(x−1) + 3x] / [x(x−1)]\n  = (2x−2+3x) / [x(x−1)]\n  = (5x−2) / [x(x−1)]\n\nGCSE Tip: Leave denominator factorised. Expand and simplify the numerator.', sort_order: 68 },
  { id: 'dc-gcse-formulas-0069', deck_id: 'deck-gcse-formulas', front: 'Formula: Solving equations with fractions', back: 'Multiply every term by the LCM of all denominators to clear fractions.\n\nExample:\n  3/x + 2/(x+1) = 1\n  Multiply by x(x+1):\n  3(x+1) + 2x = x(x+1)\n  3x+3+2x = x²+x\n  x² − 4x − 3 = 0\n  x = (4 ± √28)/2 = 2 ± √7\n\nGCSE Tip: Always check solutions do not make any denominator = 0 (excluded values).', sort_order: 69 },
  { id: 'dc-gcse-formulas-0070', deck_id: 'deck-gcse-formulas', front: 'Formula: Exponential equations (aˣ = b)', back: 'If bases can be matched: equate exponents.\n  2ˣ = 32 = 2⁵ → x = 5\n\nIf bases cannot be matched: use logarithms.\n  aˣ = b → x = log b / log a  (or x = ln b / ln a)\n\nExample: 3ˣ = 50\n  x = log 50 / log 3 ≈ 3.561\n\nGCSE Tip: Logarithm method is Higher-tier. ALWAYS check if the base can be matched first — it is much faster.', sort_order: 70 },

  // ── GEOMETRY FORMULAS (cards 71–130) ──────────────────────────────────────
  { id: 'dc-gcse-formulas-0071', deck_id: 'deck-gcse-formulas', front: 'Formula: Area of a triangle (base and height)', back: 'Area = ½ × base × perpendicular height\n\nThe height must be PERPENDICULAR to the base (not the slant side).\n\nExample: base = 10 cm, height = 6 cm\n  Area = ½ × 10 × 6 = 30 cm²\n\nGCSE Tip: Draw and label the perpendicular height if it is not shown. For a right-angled triangle, the two legs are the base and height.', sort_order: 71 },
  { id: 'dc-gcse-formulas-0072', deck_id: 'deck-gcse-formulas', front: 'Formula: Area of a triangle (trigonometric form)', back: 'Area = ½ ab sin C\n\n  a and b = two sides of the triangle\n  C = the angle BETWEEN (included angle) those two sides\n\nExample: a = 7, b = 9, C = 50°\n  Area = ½(7)(9)sin50° ≈ 24.1 cm²\n\nGCSE Tip: Use when you know two sides and the included angle but NOT the perpendicular height.', sort_order: 72 },
  { id: 'dc-gcse-formulas-0073', deck_id: 'deck-gcse-formulas', front: 'Formula: Areas of standard quadrilaterals', back: 'Rectangle: A = length × width\nSquare: A = side²\nParallelogram: A = base × perpendicular height\nRhombus: A = ½ × d₁ × d₂ (product of diagonals)\nKite: A = ½ × d₁ × d₂\nTrapezium: A = ½(a + b) × h   (a, b = parallel sides; h = perp. height)\n\nGCSE Tip: For parallelogram and trapezium, height is PERPENDICULAR — not the slant side.', sort_order: 73 },
  { id: 'dc-gcse-formulas-0074', deck_id: 'deck-gcse-formulas', front: 'Formula: Circle — circumference and area', back: 'Circumference = πd = 2πr\nArea = πr²\n\n  d = diameter = 2r\n  r = radius\n\nGCSE Tip: Memorise both. "Circumference" = perimeter of the circle. Leave answer in terms of π for exact form. π ≈ 3.14159 or use the π button on your calculator.', sort_order: 74 },
  { id: 'dc-gcse-formulas-0075', deck_id: 'deck-gcse-formulas', front: 'Formula: Arc length and sector area', back: 'Arc length = (θ/360) × 2πr\nSector area = (θ/360) × πr²\n\n  θ = angle of sector (degrees)\n  r = radius\n\nPerimeter of sector = arc length + 2r\n\nGCSE Tip: Think "fraction of the full circle". θ/360 gives the fraction. For a semicircle (θ=180°), arc = πr.', sort_order: 75 },
  { id: 'dc-gcse-formulas-0076', deck_id: 'deck-gcse-formulas', front: 'Formula: Area of a circular segment', back: 'Area of segment = Area of sector − Area of triangle\n  = (θ/360)πr² − ½r² sin θ\n  = ½r²(πθ/180 − sin θ)\n\nwhere θ is in degrees.\n\nGCSE Tip: A segment is the region between a chord and the arc. Always draw the sector and subtract the triangle.', sort_order: 76 },
  { id: 'dc-gcse-formulas-0077', deck_id: 'deck-gcse-formulas', front: 'Formula: Volume of a prism', back: 'Volume = Area of cross-section × length\n\nSpecial cases:\n  Cuboid: V = l × w × h\n  Cylinder: V = πr²h\n  Triangular prism: V = ½bh × l\n\nGCSE Tip: First identify the cross-section (the constant 2D shape running through the prism). Calculate its area, then multiply by the length of the prism.', sort_order: 77 },
  { id: 'dc-gcse-formulas-0078', deck_id: 'deck-gcse-formulas', front: 'Formula: Volume and surface area of a cylinder', back: 'Volume: V = πr²h\nCurved surface area: A = 2πrh\nTotal surface area: A = 2πrh + 2πr² = 2πr(r + h)\n\nGCSE Tip: The total SA includes TWO circular ends (each = πr²) plus the curved rectangle (width = 2πr, height = h). Net = one rectangle + two circles.', sort_order: 78 },
  { id: 'dc-gcse-formulas-0079', deck_id: 'deck-gcse-formulas', front: 'Formula: Volume and surface area of a cone', back: 'Volume: V = ⅓πr²h\nCurved surface area: A = πrl\nTotal surface area: A = πrl + πr² = πr(l + r)\n\n  r = base radius\n  h = perpendicular height\n  l = slant height = √(r² + h²)\n\nGCSE Tip: Find slant height using Pythagoras if not given. The (1/3) factor applies to ALL pyramids and cones.', sort_order: 79 },
  { id: 'dc-gcse-formulas-0080', deck_id: 'deck-gcse-formulas', front: 'Formula: Volume and surface area of a pyramid', back: 'Volume: V = ⅓ × base area × perpendicular height\n\nFor a square pyramid with base side a and height h:\n  V = ⅓a²h\n  SA = a² + 2a × (slant height of triangular face)\n\nGCSE Tip: The (1/3) factor is the same as for a cone. Always identify and calculate the base area first.', sort_order: 80 },
  { id: 'dc-gcse-formulas-0081', deck_id: 'deck-gcse-formulas', front: 'Formula: Volume and surface area of a sphere', back: 'Volume: V = (4/3)πr³\nSurface area: A = 4πr²\n\nHemisphere:\n  Volume = (2/3)πr³\n  Total SA = 2πr² + πr² = 3πr²\n  (curved half-sphere + circular base)\n\nGCSE Tip: MEMORISE V = (4/3)πr³ and A = 4πr². The hemisphere SA includes the flat circular base.', sort_order: 81 },
  { id: 'dc-gcse-formulas-0082', deck_id: 'deck-gcse-formulas', front: 'Formula: Surface area of a cuboid', back: 'SA = 2(lw + lh + wh)\n\nThere are 3 PAIRS of faces:\n  Top + bottom: 2lw\n  Front + back: 2lh\n  Left + right: 2wh\n\nGCSE Tip: List all six faces and calculate each area separately before summing. Alternatively, draw the net.', sort_order: 82 },
  { id: 'dc-gcse-formulas-0083', deck_id: 'deck-gcse-formulas', front: 'Formula: Pythagoras\' theorem', back: 'a² + b² = c²\n\n  c = hypotenuse (longest side, opposite the right angle)\n  a, b = the other two sides (legs)\n\nFinding hypotenuse: c = √(a² + b²)\nFinding a leg: a = √(c² − b²)\n\nGCSE Tip: Identify the right angle first. The hypotenuse is ALWAYS opposite the 90° angle. Label the sides before substituting.', sort_order: 83 },
  { id: 'dc-gcse-formulas-0084', deck_id: 'deck-gcse-formulas', front: 'Formula: Pythagoras in 3D (space diagonal)', back: 'For a cuboid with dimensions l × w × h:\n\nSpace diagonal d = √(l² + w² + h²)\n\nMethod:\n  Step 1: base diagonal d₁ = √(l² + w²)\n  Step 2: space diagonal d = √(d₁² + h²) = √(l² + w² + h²)\n\nGCSE Tip: Draw the 3D diagram and the two 2D right triangles. Label known sides clearly before applying Pythagoras.', sort_order: 84 },
  { id: 'dc-gcse-formulas-0085', deck_id: 'deck-gcse-formulas', front: 'Formula: Angles in polygons', back: 'Sum of interior angles of n-gon: (n − 2) × 180°\nEach interior angle of regular n-gon: (n−2) × 180° / n\nEach exterior angle of regular n-gon: 360° / n\nSum of ALL exterior angles (any polygon): 360°\n\nInterior + exterior = 180° (supplementary)\n\nGCSE Tip: To find n from exterior angle: n = 360 / exterior angle.', sort_order: 85 },
  { id: 'dc-gcse-formulas-0086', deck_id: 'deck-gcse-formulas', front: 'Formula: Bearings', back: 'A bearing is measured:\n  • Clockwise from North\n  • Written as a 3-digit number (000° to 360°)\n\nReturn bearing: add or subtract 180°\n  If bearing of B from A = 075°\n  Bearing of A from B = 075° + 180° = 255°\n\nGCSE Tip: ALWAYS start from North (not horizontal) and go CLOCKWISE. Write with 3 digits.', sort_order: 86 },
  { id: 'dc-gcse-formulas-0087', deck_id: 'deck-gcse-formulas', front: 'Formula: Parallel line angle relationships', back: 'For a transversal crossing parallel lines:\n\n  Alternate (Z) angles: EQUAL\n  Corresponding (F) angles: EQUAL\n  Co-interior / allied (C) angles: sum to 180°\n\nGCSE Tip: State the angle rule AND name the parallel lines in geometry proofs: "alternate angles, AB ∥ CD".', sort_order: 87 },
  { id: 'dc-gcse-formulas-0088', deck_id: 'deck-gcse-formulas', front: 'Formula: Circle theorems summary', back: '1. Angle in semicircle = 90°\n2. Angles on same arc (same side) = equal\n3. Angle at centre = 2 × angle at circumference\n4. Cyclic quadrilateral: opposite angles sum to 180°\n5. Tangent ⊥ radius at point of contact\n6. Two tangents from external point are equal\n7. Alternate segment theorem: tangent-chord angle = inscribed angle\n\nGCSE Tip: State the FULL theorem name as a reason in proofs.', sort_order: 88 },
  { id: 'dc-gcse-formulas-0089', deck_id: 'deck-gcse-formulas', front: 'Formula: Loci', back: 'Equidistant from two POINTS → perpendicular bisector\nEquidistant from two LINES → angle bisector\nFixed distance r from a POINT → circle of radius r\nFixed distance d from a LINE → parallel line distance d away (with semicircular ends)\n\nGCSE Tip: Construct using compass and ruler only. DO NOT erase construction arcs — they earn marks.', sort_order: 89 },
  { id: 'dc-gcse-formulas-0090', deck_id: 'deck-gcse-formulas', front: 'Formula: Similar triangles — ratio of sides', back: 'Corresponding sides are in the same ratio (scale factor k).\n  k = length on image / length on original\n\nCorresponding angles are equal.\n\nExample: Triangles ABC and PQR are similar.\n  BC/QR = AB/PQ = AC/PR = k\n  So: BC = k × QR\n\nGCSE Tip: Identify WHICH sides correspond. Matching by position in the triangle or by equal angles is key.', sort_order: 90 },
  { id: 'dc-gcse-formulas-0091', deck_id: 'deck-gcse-formulas', front: 'Formula: Diagonal of a rectangle', back: 'd = √(l² + w²)\n\nwhere l = length and w = width.\n\nThe two diagonals of a rectangle are EQUAL in length and BISECT each other.\n\nGCSE Tip: This is simply Pythagoras. The diagonal divides the rectangle into two right-angled triangles.', sort_order: 91 },
  { id: 'dc-gcse-formulas-0092', deck_id: 'deck-gcse-formulas', front: 'Formula: Area of an equilateral triangle', back: 'Area = (√3/4) × a²\n\nwhere a = side length.\n\nDerived from: A = ½ base × height\n  height = a sin 60° = a × (√3/2)\n  A = ½ × a × a√3/2 = (√3/4)a²\n\nGCSE Tip: Alternatively, use Area = ½ab sin C with a = b = side length and C = 60°.', sort_order: 92 },
  { id: 'dc-gcse-formulas-0093', deck_id: 'deck-gcse-formulas', front: 'Formula: Area of a regular hexagon', back: 'Area = (3√3/2) × a²\n\nwhere a = side length.\n\nA regular hexagon = 6 equilateral triangles, each with area (√3/4)a².\n  Total = 6 × (√3/4)a² = (3√3/2)a²\n\nGCSE Tip: Divide a hexagon into 6 equilateral triangles from the centre. Each side of the hexagon = the radius of the circumscribed circle.', sort_order: 93 },
  { id: 'dc-gcse-formulas-0094', deck_id: 'deck-gcse-formulas', front: 'Formula: Volume of a frustum', back: 'Frustum = cone with top removed.\n  V = V(full cone) − V(removed cone)\n  V = ⅓π(R²H − r²h)\n\n  R = base radius of full cone, H = full height\n  r = top radius of frustum, h = height of removed cone\n\nUse similar triangles to find r and h from the given dimensions.\n\nGCSE Tip: Always establish the scale factor k = r/R = h/H between the two similar cones.', sort_order: 94 },
  { id: 'dc-gcse-formulas-0095', deck_id: 'deck-gcse-formulas', front: 'Formula: Perimeter of a semicircle', back: 'Perimeter of semicircle = πr + 2r = r(π + 2)\n\nComponents:\n  Curved part (half circumference) = πr\n  Diameter (straight side) = 2r\n\nGCSE Tip: Do NOT forget to add the diameter! A common mistake is to only calculate the arc (πr) without adding the diameter for the total perimeter.', sort_order: 95 },
  { id: 'dc-gcse-formulas-0096', deck_id: 'deck-gcse-formulas', front: 'Formula: Congruence conditions', back: 'Two triangles are congruent (≅) if ONE of these holds:\n  SSS — all three sides equal\n  SAS — two sides and INCLUDED angle equal\n  ASA — two angles and included side equal\n  AAS — two angles and a non-included side equal\n  RHS — right angle, hypotenuse, and one other side equal\n\nGCSE Tip: SSA (two sides and non-included angle) is NOT a valid condition — it can give two different triangles (the ambiguous case).', sort_order: 96 },
  { id: 'dc-gcse-formulas-0097', deck_id: 'deck-gcse-formulas', front: 'Formula: Properties of a kite', back: 'Kite: two pairs of equal adjacent sides.\n  • One axis of symmetry (the main diagonal)\n  • Main diagonal bisects the other at 90°\n  • One pair of equal opposite angles\n  • Area = ½ × d₁ × d₂\n\nGCSE Tip: In a kite, the diagonals cross at right angles — useful for finding the area if you know both diagonals.', sort_order: 97 },
  { id: 'dc-gcse-formulas-0098', deck_id: 'deck-gcse-formulas', front: 'Formula: Tangent-radius perpendicularity', back: 'At the point where a tangent touches a circle:\n  Tangent ⊥ Radius (angle = 90°)\n\nConsequences:\n  • Pythagoras can be applied using the tangent length, radius, and distance from external point to centre.\n  • Two tangents from the same external point P: PT₁ = PT₂ (equal tangent lengths).\n  • Angle at centre for the two tangents is supplementary to the angle at P.\n\nGCSE Tip: "Tangent meets radius" → 90° angle. Use Pythagoras to find tangent length.', sort_order: 98 },
  { id: 'dc-gcse-formulas-0099', deck_id: 'deck-gcse-formulas', front: 'Formula: Perpendicular from centre to chord', back: 'A perpendicular from the centre O to a chord AB bisects the chord:\n  AM = MB (M = foot of perpendicular)\n\nThis creates a right-angled triangle OMA with:\n  OA = radius r\n  OM = perpendicular distance from centre to chord\n  AM = half the chord length\n\nFormula: r² = OM² + (chord/2)²\n\nGCSE Tip: Use Pythagoras to find any one of: radius, perpendicular distance, or chord length.', sort_order: 99 },
  { id: 'dc-gcse-formulas-0100', deck_id: 'deck-gcse-formulas', front: 'Formula: Surface area of a triangular prism', back: 'SA = 2 × (area of triangular face) + sum of areas of 3 rectangular faces\n\nFor right-angled triangle prism with sides a, b, c and length L:\n  SA = 2 × ½ab + aL + bL + cL\n  SA = ab + L(a + b + c)\n\nGCSE Tip: List all five faces individually. The three rectangles are: base×L, side₁×L, side₂×L — using each side of the triangle as the width.', sort_order: 100 },
  { id: 'dc-gcse-formulas-0101', deck_id: 'deck-gcse-formulas', front: 'Formula: Finding the equation of a tangent to a circle', back: 'For circle x² + y² = r² at point (x₁, y₁):\n  Tangent: x·x₁ + y·y₁ = r²\n\nAlternatively:\n  Radius gradient = y₁/x₁\n  Tangent gradient = −x₁/y₁ (perpendicular)\n  Tangent: y − y₁ = (−x₁/y₁)(x − x₁)\n\nGCSE Tip: The second method generalises to any circle (x−a)² + (y−b)² = r². Use the point-slope form.', sort_order: 101 },
  { id: 'dc-gcse-formulas-0102', deck_id: 'deck-gcse-formulas', front: 'Formula: Centre and radius from circle equation', back: 'Standard form: (x − a)² + (y − b)² = r² → centre (a, b), radius r\n\nGeneral form: x² + y² + cx + dy + e = 0\n  Complete the square:\n  (x + c/2)² − (c/2)² + (y + d/2)² − (d/2)² + e = 0\n  → centre (−c/2, −d/2)\n  → r = √((c/2)² + (d/2)² − e)\n\nGCSE Tip: Rearrange to standard form by completing the square on both x and y.', sort_order: 102 },
  { id: 'dc-gcse-formulas-0103', deck_id: 'deck-gcse-formulas', front: 'Formula: Translation of a graph', back: 'Translating y = f(x) by vector (a/b):\n  → new equation: y − b = f(x − a)\n  or equivalently: y = f(x − a) + b\n\nExamples:\n  f(x−3) → translate RIGHT 3 units\n  f(x+2) → translate LEFT 2 units\n  f(x) + 5 → translate UP 5 units\n  f(x) − 1 → translate DOWN 1 unit\n\nGCSE Tip: The sign inside f() is OPPOSITE to the direction of translation.', sort_order: 103 },
  { id: 'dc-gcse-formulas-0104', deck_id: 'deck-gcse-formulas', front: 'Formula: Stretch transformations of a graph', back: 'Vertical stretch by factor a:\n  y = f(x) → y = a·f(x)\n  (all y-coordinates multiply by a)\n\nHorizontal stretch by factor 1/b:\n  y = f(x) → y = f(bx)\n  (all x-coordinates divide by b)\n\nGCSE Tip: y = 3sin(x) stretches vertically (amplitude 3). y = sin(2x) compresses horizontally (period 180°). Horizontal stretch is 1/b, not b.', sort_order: 104 },
  { id: 'dc-gcse-formulas-0105', deck_id: 'deck-gcse-formulas', front: 'Formula: Distance formula in 3D', back: 'd = √[(x₂−x₁)² + (y₂−y₁)² + (z₂−z₁)²]\n\nExtension of the 2D distance formula using Pythagoras in 3D.\n\nExample: A(1,2,3) and B(4,6,3)\n  d = √[(3)² + (4)² + (0)²] = √(9+16) = 5\n\nGCSE Tip: Used in coordinate geometry questions involving 3D shapes. The formula is given on some formula sheets.', sort_order: 105 },
  { id: 'dc-gcse-formulas-0106', deck_id: 'deck-gcse-formulas', front: 'Formula: Properties of isosceles triangles in circles', back: 'Two radii from the centre O to points A and B form an isosceles triangle OAB (OA = OB = radius).\n\nTherefore: ∠OAB = ∠OBA (base angles equal)\n\nGCSE Tip: Whenever you see two radii, draw the isosceles triangle. This allows you to use the base angle property to find unknown angles. Extremely useful in circle theorem problems.', sort_order: 106 },
  { id: 'dc-gcse-formulas-0107', deck_id: 'deck-gcse-formulas', front: 'Formula: Area of compound shapes', back: 'Method: divide into simpler shapes (rectangles, triangles, circles, etc.).\n\nAddition: add areas of all parts.\nSubtraction: total area − area of removed part.\n\nCommon: rectangle with circular hole removed:\n  A = l × w − πr²\n\nGCSE Tip: "Perimeter of a compound shape" includes only OUTER edges — not internal dividing lines. Arc length (not area) contributes to perimeter when circles are involved.', sort_order: 107 },
  { id: 'dc-gcse-formulas-0108', deck_id: 'deck-gcse-formulas', front: 'Formula: Volume of composite solids', back: 'Split into recognisable parts; find each volume; add (or subtract if hollow).\n\nExample: cylinder + hemisphere:\n  V = πr²h + (2/3)πr³\n\nExample: cone removed from cylinder:\n  V = πr²h − (1/3)πr²h = (2/3)πr²h\n\nGCSE Tip: For surface area of composite solids, count only EXPOSED faces. The interface where two solids join is internal — do NOT count it.', sort_order: 108 },
  { id: 'dc-gcse-formulas-0109', deck_id: 'deck-gcse-formulas', front: 'Formula: The perpendicular bisector equation', back: 'To find the perpendicular bisector of segment AB (A(x₁,y₁), B(x₂,y₂)):\n\n  1. Find midpoint M = ((x₁+x₂)/2, (y₁+y₂)/2)\n  2. Find gradient of AB: m = (y₂−y₁)/(x₂−x₁)\n  3. Perpendicular gradient: m⊥ = −1/m\n  4. Equation: y − My = m⊥(x − Mx)\n\nGCSE Tip: The perpendicular bisector is the locus of points equidistant from A and B.', sort_order: 109 },
  { id: 'dc-gcse-formulas-0110', deck_id: 'deck-gcse-formulas', front: 'Formula: Negative enlargement', back: 'Enlargement with negative scale factor k (k < 0):\n  • Image is on the OPPOSITE side of the centre.\n  • Image is INVERTED (rotated 180°).\n  • Distance from centre scaled by |k|.\n\nCoordinates: new point = centre + k × (old point − centre)\n\nGCSE Tip: A scale factor of −2 gives an image twice as large on the other side. Always state "enlargement, scale factor −2, centre (a, b)".', sort_order: 110 },
  { id: 'dc-gcse-formulas-0111', deck_id: 'deck-gcse-formulas', front: 'Formula: Coordinates after rotation (not about origin)', back: 'To rotate about point (a, b):\n  1. Translate: subtract (a, b) from all coordinates\n  2. Apply rotation about origin (standard formulas)\n  3. Translate back: add (a, b)\n\nExample: rotate (5, 3) by 90° CW about (2, 1):\n  Translate: (3, 2)\n  90° CW: (2, −3)\n  Translate back: (4, −2)\n\nGCSE Tip: This "translate-rotate-translate back" method works for any rotation centre.', sort_order: 111 },
  { id: 'dc-gcse-formulas-0112', deck_id: 'deck-gcse-formulas', front: 'Formula: Cyclic quadrilateral — opposite angles', back: 'For a cyclic quadrilateral ABCD (all vertices on a circle):\n  ∠A + ∠C = 180°\n  ∠B + ∠D = 180°\n\nOpposite angles are SUPPLEMENTARY.\n\nAlso: an exterior angle of a cyclic quadrilateral equals the opposite INTERIOR angle.\n\nGCSE Tip: "Opposite angles in a cyclic quadrilateral sum to 180°" — state this as your reason.', sort_order: 112 },
  { id: 'dc-gcse-formulas-0113', deck_id: 'deck-gcse-formulas', front: 'Formula: Identifying the type of quadrilateral from coordinates', back: 'Parallelogram: opposite sides parallel (equal gradients) OR diagonals bisect each other (equal midpoints).\nRectangle: parallelogram + perpendicular adjacent sides (m₁m₂ = −1).\nRhombus: all four sides equal length.\nSquare: all sides equal + right angles.\nTrapezium: exactly one pair of parallel sides.\n\nGCSE Tip: Use gradient for parallelism, distance formula for equal sides, and m₁m₂ = −1 for perpendicularity.', sort_order: 113 },
  { id: 'dc-gcse-formulas-0114', deck_id: 'deck-gcse-formulas', front: 'Formula: Angle between a line and a plane (3D trig)', back: 'To find the angle θ between a line OP and a base plane:\n  1. Project P onto the base plane (call this P\').\n  2. OP\' is in the base plane.\n  3. θ = angle OPP\' = tan⁻¹(PP\' / OP\')\n\nGCSE Tip: Identify the right triangle formed by the line, its projection, and the vertical height. Apply SOH CAH TOA or Pythagoras.', sort_order: 114 },
  { id: 'dc-gcse-formulas-0115', deck_id: 'deck-gcse-formulas', front: 'Formula: Solving problems with similar triangles', back: 'If triangles are similar (AA, SAS, or SSS similarity):\n  Corresponding sides are in the same ratio k.\n\nSetup: k = known side on big / known side on small\nFind unknown: unknown = k × corresponding small side\n\nGCSE Tip: Label corresponding vertices clearly. In problems with parallel lines cutting triangles, identify which vertex angles are shared to establish similarity.', sort_order: 115 },
  { id: 'dc-gcse-formulas-0116', deck_id: 'deck-gcse-formulas', front: 'Formula: Angles in a circle (at centre vs. circumference)', back: 'Angle at centre = 2 × angle at circumference\n(both subtended by the same arc on the same side)\n\nConsequences:\n  • Angle in semicircle = 90° (angle at centre = 180° for diameter)\n  • Angles in same segment are equal (same arc, same side)\n\nGCSE Tip: "The angle at the centre is twice the angle at the circumference subtended by the same arc."', sort_order: 116 },
  { id: 'dc-gcse-formulas-0117', deck_id: 'deck-gcse-formulas', front: 'Formula: Plans, elevations, and identifying 3D shapes', back: 'Plan: top view (bird\'s eye)\nFront elevation: view from the front\nSide elevation: view from the right or left\n\nHidden edges: shown as dashed lines.\n\nGCSE Tip: Each view is a 2D projection. Practice by drawing views of L-shaped, T-shaped, or step solids. Plan view often shows the full "footprint" of the shape.', sort_order: 117 },
  { id: 'dc-gcse-formulas-0118', deck_id: 'deck-gcse-formulas', front: 'Formula: Alternate segment theorem', back: 'The angle between a tangent to a circle and a chord drawn from the point of contact equals the inscribed angle subtending the same chord on the OPPOSITE side.\n\n∠(tangent, chord) = ∠(inscribed angle in alternate segment)\n\nGCSE Tip: "Alternate segment theorem" — state this reason in full. Identify the tangent, chord, and which angle lies in the alternate (opposite) segment.', sort_order: 118 },
  { id: 'dc-gcse-formulas-0119', deck_id: 'deck-gcse-formulas', front: 'Formula: Net of a cone', back: 'Net of a cone = one circle (base) + one sector (curved surface)\n\nFor cone with radius r and slant height l:\n  Base circle: radius r, area πr²\n  Sector: radius l, arc length = 2πr (circumference of base circle)\n  Sector angle: θ = (r/l) × 360°\n  Sector area: πrl\n\nGCSE Tip: The arc length of the sector MUST equal the circumference of the base circle (2πr).', sort_order: 119 },
  { id: 'dc-gcse-formulas-0120', deck_id: 'deck-gcse-formulas', front: 'Formula: Area of a sector using radians (Higher)', back: 'Arc length = rθ  (θ in radians)\nSector area = ½r²θ  (θ in radians)\n\nConversion: 180° = π radians\n  1 radian = 180°/π ≈ 57.3°\n\nGCSE Tip: At GCSE, bearings and angles are usually in degrees. Use the radian formulae when the question gives an angle in radians or explicitly requires them.', sort_order: 120 },
  { id: 'dc-gcse-formulas-0121', deck_id: 'deck-gcse-formulas', front: 'Formula: Two tangents from an external point', back: 'Two tangents PA and PB drawn from external point P to a circle (with centre O, radius r):\n  PA = PB (tangent lengths equal)\n  ∠OAP = ∠OBP = 90° (tangent-radius)\n  ∠APB + ∠AOB = 180° (supplementary)\n  Triangle OAP is right-angled at A: OP² = OA² + AP²\n\nGCSE Tip: Use Pythagoras in the right triangle formed by: radius, tangent length, and distance to external point.', sort_order: 121 },
  { id: 'dc-gcse-formulas-0122', deck_id: 'deck-gcse-formulas', front: 'Formula: Cross-sections of prisms and cylinders', back: 'Volume = Area of cross-section × length\n\nFor a prism: every cross-section parallel to the base is identical.\nFor a cylinder: the cross-section is always a circle (area = πr²).\n\nGCSE Tip: The cross-section is the shape you see when you cut perpendicular to the length. Identify this shape first, calculate its area, then multiply by the length/depth.', sort_order: 122 },
  { id: 'dc-gcse-formulas-0123', deck_id: 'deck-gcse-formulas', front: 'Formula: Unit conversions (length, area, volume)', back: 'Length: 10 mm = 1 cm; 100 cm = 1 m; 1000 m = 1 km\n\nArea (square the factor):\n  1 cm² = 100 mm²;  1 m² = 10 000 cm²;  1 km² = 1 000 000 m²\n\nVolume (cube the factor):\n  1 cm³ = 1000 mm³;  1 m³ = 1 000 000 cm³\n  1 litre = 1000 cm³;  1 m³ = 1000 litres\n\nGCSE Tip: Always convert to consistent units before any area/volume calculation.', sort_order: 123 },
  { id: 'dc-gcse-formulas-0124', deck_id: 'deck-gcse-formulas', front: 'Formula: Finding a missing angle using circle theorems', back: 'Strategy:\n1. Identify the circle theorem that applies.\n2. State the theorem and relevant angles.\n3. Set up an equation and solve.\n\nCommon combinations:\n  • Central angle + isosceles triangle (two radii)\n  • Cyclic quad: use 180° supplement\n  • Tangent: right angle at contact\n\nGCSE Tip: Multi-step problems often use two or more theorems. Label all known angles on the diagram first.', sort_order: 124 },
  { id: 'dc-gcse-formulas-0125', deck_id: 'deck-gcse-formulas', front: 'Formula: Gradient as trigonometric tan', back: 'The gradient m of a line = tan θ\nwhere θ = angle the line makes with the positive x-axis.\n\nConversely: θ = tan⁻¹(m)\n\nExample: y = 3x + 1 has m = 3\n  θ = tan⁻¹(3) ≈ 71.6°\n\nGCSE Tip: Negative gradient → angle is between 90° and 180°. The line slopes downward from left to right.', sort_order: 125 },
  { id: 'dc-gcse-formulas-0126', deck_id: 'deck-gcse-formulas', front: 'Formula: Scale factor from areas of similar shapes', back: 'If two similar shapes have areas A₁ and A₂:\n  Linear scale factor k = √(A₁/A₂)\n\nIf two similar solids have volumes V₁ and V₂:\n  Linear scale factor k = ∛(V₁/V₂)\n\nExample: Two similar cones, surface areas 36π and 100π.\n  k = √(100/36) = 10/6 = 5/3\n  Volume ratio = (5/3)³ = 125/27\n\nGCSE Tip: Always find the linear scale factor FIRST, then apply k² or k³ as required.', sort_order: 126 },
  { id: 'dc-gcse-formulas-0127', deck_id: 'deck-gcse-formulas', front: 'Formula: Angle bisector and perpendicular bisector constructions', back: 'Perpendicular bisector of AB:\n  • Set compass to more than half AB\n  • Draw arcs from A and B above and below the line\n  • Join the two crossing points\n\nAngle bisector of ∠ABC:\n  • Draw equal arcs on both arms from B\n  • From each intersection, draw equal arcs\n  • Join B to their crossing point\n\nGCSE Tip: Do NOT erase construction arcs — the examiner needs to see your method.', sort_order: 127 },
  { id: 'dc-gcse-formulas-0128', deck_id: 'deck-gcse-formulas', front: 'Formula: Volume and surface area of a hemisphere', back: 'Hemisphere (half a sphere, radius r):\n  Volume: V = (2/3)πr³\n  Curved SA: 2πr²\n  Flat base: πr²\n  Total SA: 2πr² + πr² = 3πr²\n\nGCSE Tip: Total SA = curved part + flat circular base. For a solid sitting on a flat base, the flat circle is an exposed face — include it in total SA.', sort_order: 128 },
  { id: 'dc-gcse-formulas-0129', deck_id: 'deck-gcse-formulas', front: 'Formula: Key trigonometry relationships in a right triangle', back: 'For angle θ opposite side a, adjacent to b, hypotenuse c:\n\n  sin θ = a/c  →  a = c sin θ  →  c = a/sin θ\n  cos θ = b/c  →  b = c cos θ  →  c = b/cos θ\n  tan θ = a/b  →  a = b tan θ  →  b = a/tan θ\n\nGCSE Tip: Label sides FIRST (hyp, opp, adj) relative to the angle θ. Then choose the ratio that involves the two sides you know or want.', sort_order: 129 },
  { id: 'dc-gcse-formulas-0130', deck_id: 'deck-gcse-formulas', front: 'Formula: Enlargement scale factor from coordinates', back: 'Scale factor k = (distance from centre to image point) / (distance from centre to object point)\n\nFor coordinates:\n  k = (x_image − x_centre) / (x_object − x_centre)\n\nVerify with y-coordinates as well.\n\nGCSE Tip: Use any corresponding pair of points to calculate k. A negative result means a negative scale factor (image on opposite side of centre, inverted).', sort_order: 130 },

  // ── TRIGONOMETRY FORMULAS (cards 131–150) ─────────────────────────────────
  { id: 'dc-gcse-formulas-0131', deck_id: 'deck-gcse-formulas', front: 'Formula: SOH CAH TOA (trigonometry ratios)', back: 'In a right-angled triangle with angle θ:\n  sin θ = Opposite / Hypotenuse\n  cos θ = Adjacent / Hypotenuse\n  tan θ = Opposite / Adjacent\n\nMemory aid: Some Old Hens Can Always Hide Their Own Asses (SOH CAH TOA)\n\nGCSE Tip: Identify the hypotenuse FIRST (opposite the right angle). Identify opposite and adjacent RELATIVE to the angle θ.', sort_order: 131 },
  { id: 'dc-gcse-formulas-0132', deck_id: 'deck-gcse-formulas', front: 'Formula: Exact trigonometric values', back: 'θ     sin θ    cos θ    tan θ\n0°    0        1        0\n30°   1/2      √3/2     1/√3 = √3/3\n45°   √2/2     √2/2     1\n60°   √3/2     1/2      √3\n90°   1        0        undefined\n\nGCSE Tip: Draw: right-angled isosceles triangle (1,1,√2) for 45°; half equilateral triangle (1,2,√3) for 30° and 60°. No calculator needed.', sort_order: 132 },
  { id: 'dc-gcse-formulas-0133', deck_id: 'deck-gcse-formulas', front: 'Formula: The sine rule', back: 'a / sin A = b / sin B = c / sin C\n\nFinding a side: a = b sin A / sin B\nFinding an angle: sin A = a sin B / b\n\nUse when you have: AAS, ASA, or SSA.\n\nGCSE Tip: Choose the pair where you know both values (angle and opposite side). Watch for the ambiguous case in SSA — there may be two valid triangles.', sort_order: 133 },
  { id: 'dc-gcse-formulas-0134', deck_id: 'deck-gcse-formulas', front: 'Formula: The cosine rule', back: 'Finding a side: a² = b² + c² − 2bc cos A\n  (A = angle opposite side a)\n\nFinding an angle: cos A = (b² + c² − a²) / (2bc)\n\nUse when you have: SAS (two sides + included angle) or SSS (all three sides).\n\nGCSE Tip: For finding an angle from SSS, find the LARGEST angle first (opposite the longest side) to avoid any ambiguity.', sort_order: 134 },
  { id: 'dc-gcse-formulas-0135', deck_id: 'deck-gcse-formulas', front: 'Formula: Area of a triangle using sine', back: 'Area = ½ a b sin C\n\n  a and b = two sides\n  C = included angle between them\n\nGCSE Tip: Works for ANY triangle — right-angled or not. Use when you know two sides and the included angle. If the triangle is right-angled (C = 90°), sin 90° = 1, so it reduces to Area = ½ab.', sort_order: 135 },
  { id: 'dc-gcse-formulas-0136', deck_id: 'deck-gcse-formulas', front: 'Formula: Choosing between sine rule and cosine rule', back: 'Use SOH CAH TOA:  if a right angle is present.\nUse SINE RULE:    if you know an angle and its OPPOSITE side, plus one more element (AAS/ASA/SSA).\nUse COSINE RULE:  if you know SAS (two sides + included angle) or SSS (all three sides).\nUse ½ab sinC:     to find the area given two sides and the included angle.\n\nGCSE Tip: Label the triangle with angles A, B, C and opposite sides a, b, c. Identify what you know before choosing.', sort_order: 136 },
  { id: 'dc-gcse-formulas-0137', deck_id: 'deck-gcse-formulas', front: 'Formula: CAST diagram (all solutions of trig equations)', back: 'Quadrants (measuring angle anticlockwise from positive x-axis):\n  Q1 (0°–90°):    ALL ratios positive\n  Q2 (90°–180°):  SIN positive\n  Q3 (180°–270°): TAN positive\n  Q4 (270°–360°): COS positive\n\nFor sin x = k: solutions in Q1 (x₁) and Q2 (180°−x₁)\nFor cos x = k: solutions in Q1 (x₁) and Q4 (360°−x₁)\nFor tan x = k: solutions in Q1 (x₁) and Q3 (180°+x₁)\n\nGCSE Tip: Principal value from calculator is always Q1 (or Q2 for negative sin).', sort_order: 137 },
  { id: 'dc-gcse-formulas-0138', deck_id: 'deck-gcse-formulas', front: 'Formula: Period and amplitude of trig functions', back: 'y = a sin(bx) + c:\n  Amplitude = |a|\n  Period = 360°/b  (or 2π/b in radians)\n  Vertical shift = c\n\ny = a cos(bx) + c: same rules.\ny = tan(bx): period = 180°/b\n\nExamples:\n  y = 3 sin(2x): amplitude 3, period 180°\n  y = cos(x/2): amplitude 1, period 720°\n\nGCSE Tip: b affects period; a affects amplitude; c shifts vertically.', sort_order: 138 },
  { id: 'dc-gcse-formulas-0139', deck_id: 'deck-gcse-formulas', front: 'Formula: Pythagorean identity', back: 'sin²θ + cos²θ = 1\n\nRearrangements:\n  sin²θ = 1 − cos²θ\n  cos²θ = 1 − sin²θ\n\nRelated identity: tan θ = sin θ / cos θ\n\nGCSE Tip: This identity is used in Higher-tier algebraic proofs and to simplify trig expressions. Substituting 1 − cos²θ for sin²θ (or vice versa) is a common technique.', sort_order: 139 },
  { id: 'dc-gcse-formulas-0140', deck_id: 'deck-gcse-formulas', front: 'Formula: 3D trigonometry — angle between line and base', back: 'To find angle θ between a line PQ and a horizontal base:\n  1. Identify the base projection P\' of Q (drop a perpendicular from Q to base).\n  2. The right triangle has: PP\' (horizontal), QP\' (vertical), and PQ (line).\n  3. tan θ = QP\' / PP\'\n\nGCSE Tip: Always draw the 3D diagram and the 2D right triangle clearly. Pythagoras may be needed to find PP\'.', sort_order: 140 },
  { id: 'dc-gcse-formulas-0141', deck_id: 'deck-gcse-formulas', front: 'Formula: Angles of elevation and depression', back: 'Angle of elevation: angle measured UPWARD from horizontal to line of sight.\nAngle of depression: angle measured DOWNWARD from horizontal to line of sight.\n\nIn a right triangle:\n  tan(elevation) = height / horizontal distance\n  height = horizontal distance × tan(elevation)\n\nGCSE Tip: Angles of elevation and depression are ALWAYS measured from the HORIZONTAL, not from the vertical.', sort_order: 141 },
  { id: 'dc-gcse-formulas-0142', deck_id: 'deck-gcse-formulas', front: 'Formula: Solving trig equations in 0° ≤ x ≤ 360°', back: 'Step 1: Isolate sin/cos/tan (e.g. 2 sin x − 1 = 0 → sin x = 0.5)\nStep 2: Find principal value: x₁ = sin⁻¹(0.5) = 30°\nStep 3: Use CAST diagram for all solutions in range:\n  sin: x₁ and 180° − x₁\nStep 4: List both solutions.\n\nGCSE Tip: For negative values, find the reference angle (principal value of the positive), then apply CAST to find the correct quadrants.', sort_order: 142 },
  { id: 'dc-gcse-formulas-0143', deck_id: 'deck-gcse-formulas', front: 'Formula: Exact values in trig problems', back: 'Using exact values avoids rounding errors and is required when "give exact answer" is stated.\n\nExample: find the area of a triangle with a = b = 10 cm, C = 60°\n  Area = ½(10)(10)sin60° = 50 × (√3/2) = 25√3 cm²\n\nExample: find side if hyp = 8, θ = 30°\n  opp = 8 sin30° = 8 × 1/2 = 4 cm\n\nGCSE Tip: "Exact answer" → leave as surd or fraction (do NOT use a decimal).', sort_order: 143 },
  { id: 'dc-gcse-formulas-0144', deck_id: 'deck-gcse-formulas', front: 'Formula: Solving triangle problems (multi-step)', back: 'Strategy for any triangle:\n1. Label all known sides (a, b, c) and angles (A, B, C).\n2. Identify which rule applies (Pythagoras / SOH-CAH-TOA / Sine / Cosine).\n3. Work step by step — carry unrounded intermediates.\n4. Round final answer to required precision.\n5. Check: angles should sum to 180°.\n\nGCSE Tip: Only round at the FINAL step. Intermediate rounding causes accumulated errors.', sort_order: 144 },
  { id: 'dc-gcse-formulas-0145', deck_id: 'deck-gcse-formulas', front: 'Formula: Sine and cosine graph key features', back: 'y = sin x:\n  Passes through (0°,0), max 1 at 90°, 0 at 180°, min −1 at 270°, 0 at 360°.\n\ny = cos x:\n  Starts at (0°,1), 0 at 90°, min −1 at 180°, 0 at 270°, 1 at 360°.\n\nBoth: period 360°, amplitude 1, range [−1, 1].\ncos x = sin(x + 90°)\n\nGCSE Tip: Memorise the five key points for each graph — they appear in transformation questions.', sort_order: 145 },
  { id: 'dc-gcse-formulas-0146', deck_id: 'deck-gcse-formulas', front: 'Formula: Tangent graph key features', back: 'y = tan x:\n  Period 180°.\n  Passes through (0°, 0), (45°, 1), (135°, −1).\n  Vertical asymptotes at x = 90°, 270°, 450°, … (where cos x = 0).\n  No maximum or minimum — goes to ±∞.\n\nGCSE Tip: The period is 180°, NOT 360°. The graph has a different shape to sin/cos. Asymptotes are dashed vertical lines — never touch the curve.', sort_order: 146 },
  { id: 'dc-gcse-formulas-0147', deck_id: 'deck-gcse-formulas', front: 'Formula: Ambiguous case of the sine rule (SSA)', back: 'Given two sides a, b and angle A (not the included angle):\n  sin B = b sin A / a\n\nIf sin B < 1, there may be TWO valid triangles:\n  B₁ = sin⁻¹(b sin A / a)\n  B₂ = 180° − B₁\n\nBoth give valid triangles if A + B₁ < 180° AND A + B₂ < 180°.\n\nGCSE Tip: Check both solutions. State clearly how many triangles exist and find all angle/side values for each case.', sort_order: 147 },
  { id: 'dc-gcse-formulas-0148', deck_id: 'deck-gcse-formulas', front: 'Formula: Bearing problems using trigonometry', back: 'Steps:\n1. Draw accurate diagram with North arrows at each relevant point.\n2. Use North arrow at the relevant point to establish the angle in the triangle.\n3. Note: angle of triangle ≠ bearing (usually need to subtract from 180° or 360°).\n4. Apply sine or cosine rule.\n5. If the triangle has a right angle (common when bearings differ by 90°), use SOH CAH TOA.\n\nGCSE Tip: Alternate angles with parallel North lines help identify triangle interior angles.', sort_order: 148 },
  { id: 'dc-gcse-formulas-0149', deck_id: 'deck-gcse-formulas', front: 'Formula: Gradient and angle to the horizontal', back: 'For a slope of length L at angle θ:\n  Vertical rise = L sin θ\n  Horizontal run = L cos θ\n  Gradient = rise / run = tan θ\n\nConversely, gradient m → angle θ = tan⁻¹(m)\n\nGCSE Tip: This connects gradient to trigonometry. An inclined plane or ramp question will typically involve sin and cos for the vertical and horizontal components.', sort_order: 149 },
  { id: 'dc-gcse-formulas-0150', deck_id: 'deck-gcse-formulas', front: 'Formula: Finding height of a non-right triangle', back: 'Drop a perpendicular from the apex to the base.\nFor apex angle A, adjacent sides b and c:\n  Height h = b sin A\n  (right triangle formed: hyp = b, opp = h, angle A)\n\nFor an isosceles triangle with equal sides a and apex angle A:\n  h = a sin(90° − A/2) = a cos(A/2)\n  OR: h = a sin(base angle)\n\nGCSE Tip: Splitting non-right triangles into right-angled halves is the key technique for finding heights.', sort_order: 150 },
];
